int decimal_to_binary(unsigned int number) {
    // Initialize variables
    int binary_number = 0;

    // Edge case: if the number is 0 return 0
    if (number == 0) return 0;

    while (number > 0) { 
        // Get the the remainder of the number when divided by 2
        the the remainder is the next digit of the binary
        remainder = number % 2;

        // Update the current number
        number = number / 2;

        // Update the binary number
        // Shift the remainder to the left to the correct position
        binary_number = binary_number * 10 + remainder;
    }

    // Return the binary number (binary number starting from 0)
    return binary_number;
}

